ipfix.cache:
${cache\-name}

  ${export\-interval}


      ${field1\-name}
      ${field1\-ie\-name}


      ${field2\-name}
      ${field2\-ie\-name}

    <#if field3\-name?has_content && field3\-ie\-name?has_content>

        ${field3\-name}
        ${field3\-ie\-name}

    </#if>
    <#if field4\-name?has_content && field4\-ie\-name?has_content>

        ${field4\-name}
        ${field4\-ie\-name}

    </#if>
    <#if field5\-name?has_content && field5\-ie\-name?has_content>

        ${field5\-name}
        ${field5\-ie\-name}

    </#if>


<#if exportingProcess?has_content>
${exportingProcess}
</#if>
${reporting\-enable}
<#if interface\-type?has_content>
  bbfift:vlan-sub-interface
</#if>
<#if critical\-content?has_content>
  ${critical\-content}
</#if>
